format:
{% if active %}<active/>{% endif %}{% if state == 'prompt' %}<pulse>{% endif %}{% if is_claude | default(true) %}<span size='xx-large' weight='bold' foreground='#cdd6f4'>{{ shortcut }}</span> <status state="{{ state }}" level="{{ idle_level | default(0) }}"/> <span weight='bold' foreground='#89b4fa'>{{ folder }}</span>{% if state == 'idle' and idle_ago %} <span size='small' foreground='#9399b2'>{{ idle_ago }} ago</span>{% endif %}
<tickerbox width="210">{% if unpushed %}<span weight='bold' foreground='#a6e3a1'>↑{{ unpushed }}</span>  {% endif %}<span foreground='#cdd6f4'>{{ title }}</span></tickerbox>{% else %}{% if '/' in app_icon %}<icon hero="1" src="{{ app_icon }}"/>{% else %}<icon hero="1" name="{{ app_icon | default('app') }}"/>{% endif %}<span size='large' weight='bold' foreground='#cdd6f4'>{{ shortcut }}</span><sep/><span weight='bold' foreground='#89b4fa'>{{ app }}</span>
<tickerbox width="150"><span foreground='#cdd6f4'>{{ title }}</span></tickerbox>{% endif %}{% if state == 'prompt' %}</pulse>{% endif %}
